noncompliant:
#include <sys/stat.h>
#include <fcntl.h>

// Setting overly permissive file permissions
int fd = open("sensitive.txt", O_CREAT | O_WRONLY, 0777); // Noncompliant: world readable/writable
mkdir("private_dir", 0755); // Noncompliant: world readable
chmod("config.conf", S_IRWXU | S_IRWXG | S_IRWXO); // Noncompliant: 777 permissions

compliant:
#include <sys/stat.h>
#include <fcntl.h>

// Setting restrictive file permissions
int fd = open("sensitive.txt", O_CREAT | O_WRONLY, 0600); // Compliant: owner read/write only
mkdir("private_dir", 0700); // Compliant: owner access only
chmod("config.conf", S_IRUSR | S_IWUSR); // Compliant: owner read/write only
